import sys

a = int(sys.stdin.readline())
b = sys.stdin.readline().split(' ')
b = [int(i) for i in b]
b.sort()
c = a//b[0]
d = a//b[8]
if c>d:
    for i in range(0,d):
        print(b[0],end='')
    for i in range(0,c-d):
        print(b[8],end='')
elif c<d:
    for i in range(0,c):
        print(b[0],end='')
    for i in range(0,d-c):
        print(b[8],end='')
else:
    for i in range(0,c):
        print(b[0],end='')
    for i in range(0,d):
        print(b[8],end='')
